def parse_commit(commit_hash: str) -> tuple[str, str, str, list[tuple[str, str]]]:
    """Parse a commit file and return (parent, timestamp, message, files).

    Files is a list of (filename, blobhash) tuples.
    """
    commit_path: str = os.path.join(COMMITS_DIR, commit_hash)
    with open(commit_path, "r") as f:
        text: str = f.read()

    parent: str = ""
    timestamp: str = ""
    message: str = ""
    files: list[tuple[str, str]] = []

    in_files: bool = False
    for line in text.splitlines():
        if in_files:
            stripped: str = line.strip()
            if stripped:
                parts: list[str] = stripped.split(" ", 1)
                if len(parts) == 2:
                    files.append((parts[0], parts[1]))
        elif line.startswith("parent: "):
            parent = line[len("parent: "):]
        elif line.startswith("timestamp: "):
            timestamp = line[len("timestamp: "):]
        elif line.startswith("message: "):
            message = line[len("message: "):]
        elif line == "files:":
            in_files = True

    return parent, timestamp, message, files


def cmd_status() -> None:
    """Show staged files."""
    indexed: list[str] = []
    if os.path.isfile(INDEX_FILE):
        with open(INDEX_FILE, "r") as f:
            indexed = [line.strip() for line in f if line.strip()]

    print("Staged files:")
    if indexed:
        for name in indexed:
            print(name)
    else:
        print("(none)")


def cmd_log() -> None:
    """Show commit history."""
    if not os.path.isfile(HEAD_FILE):
        print("No commits")
        return

    with open(HEAD_FILE, "r") as f:
        current: str = f.read().strip()

    if not current:
        print("No commits")
        return

    first: bool = True
    while current and current != "NONE":
        commit_path: str = os.path.join(COMMITS_DIR, current)
        if not os.path.isfile(commit_path):
            break

        parent_hash: str
        timestamp_str: str
        message_str: str
        parent_hash, timestamp_str, message_str, _ = parse_commit(current)

        if not first:
            print()
        first = False

        print(f"commit {current}")
        print(f"Date: {timestamp_str}")
        print(f"Message: {message_str}")

        current = parent_hash if parent_hash != "NONE" else ""


def cmd_diff(commit1: str, commit2: str) -> None:
    """Compare two commits."""
    for ch in [commit1, commit2]:
        if not os.path.isfile(os.path.join(COMMITS_DIR, ch)):
            print("Invalid commit")
            sys.exit(1)

    _, _, _, files1 = parse_commit(commit1)
    _, _, _, files2 = parse_commit(commit2)

    map1: dict[str, str] = dict(files1)
    map2: dict[str, str] = dict(files2)

    all_files: list[str] = sorted(set(list(map1.keys()) + list(map2.keys())))

    for fname in all_files:
        in1: bool = fname in map1
        in2: bool = fname in map2
        if in1 and not in2:
            print(f"Removed: {fname}")
        elif not in1 and in2:
            print(f"Added: {fname}")
        elif in1 and in2 and map1[fname] != map2[fname]:
            print(f"Modified: {fname}")


def cmd_checkout(commit_hash: str) -> None:
    """Checkout a commit."""
    if not os.path.isfile(os.path.join(COMMITS_DIR, commit_hash)):
        print("Invalid commit")
        sys.exit(1)

    _, _, _, files = parse_commit(commit_hash)

    for fname, blob_hash in files:
        blob_path: str = os.path.join(OBJECTS_DIR, blob_hash)
        with open(blob_path, "rb") as f:
            content: bytes = f.read()
        with open(fname, "wb") as f:
            f.write(content)

    with open(HEAD_FILE, "w") as f:
        f.write(commit_hash)

    with open(INDEX_FILE, "w") as f:
        pass

    print(f"Checked out {commit_hash}")


def cmd_reset(commit_hash: str) -> None:
    """Reset HEAD to a commit."""
    if not os.path.isfile(os.path.join(COMMITS_DIR, commit_hash)):
        print("Invalid commit")
        sys.exit(1)

    with open(HEAD_FILE, "w") as f:
        f.write(commit_hash)

    with open(INDEX_FILE, "w") as f:
        pass

    print(f"Reset to {commit_hash}")


def cmd_rm(filename: str) -> None:
    """Remove a file from the staging index."""
    indexed: list[str] = []
    if os.path.isfile(INDEX_FILE):
        with open(INDEX_FILE, "r") as f:
            indexed = [line.strip() for line in f if line.strip()]

    if filename not in indexed:
        print("File not in index")
        sys.exit(1)

    indexed.remove(filename)
    with open(INDEX_FILE, "w") as f:
        for name in indexed:
            f.write(name + "\n")


def cmd_show(commit_hash: str) -> None:
    """Show commit details."""
    if not os.path.isfile(os.path.join(COMMITS_DIR, commit_hash)):
        print("Invalid commit")
        sys.exit(1)

    _, timestamp, message, files = parse_commit(commit_hash)

    print(f"commit {commit_hash}")
    print(f"Date: {timestamp}")
    print(f"Message: {message}")
    print("Files:")
    for fname, blob_hash in sorted(files, key=lambda x: x[0]):
        print(f"  {fname} {blob_hash}")


def main() -> None:
    """Entry point."""
    if len(sys.argv) < 2:
        print("Usage: minigit <command>")
        sys.exit(1)

    command: str = sys.argv[1]

    if command == "init":
        cmd_init()
    elif command == "add":
        if len(sys.argv) < 3:
            print("Usage: minigit add <file>")
            sys.exit(1)
